+func newCrossTestSocket(t *testing.T) *Tmux {
+	t.Helper()
+	if !hasTmux() {
+		t.Skip("tmux not installed")
+	}
+	tm := NewTmuxWithSocket(crossSocket)
+	t.Cleanup(func() {
+		_ = tm.KillServer()
+	})
