+		fmt.Sprintf("gt-test-multi-d2-%d", os.Getpid()),
+	}
+	crossSessions := []string{
+		fmt.Sprintf("gt-test-multi-c1-%d", os.Getpid()),
+		fmt.Sprintf("gt-test-multi-c2-%d", os.Getpid()),
+	}
+
+	for _, name := range defaultSessions {
